import React, { useState } from "react";
import api from "../api";

function AddEditItem() {
  const [form, setForm] = useState({
    title: "",
    description: "",
    category: "",
    location: "",
    date: "",
    status: "LOST",
    imageUrl: "",
    expiryDate: "",
    contactInfo: ""
  });
  const [message, setMessage] = useState("");

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const userId = localStorage.getItem("userId");
    if (!userId) {
      setMessage("Please login first.");
      return;
    }
    try {
      const response = await api.post(`/items?userId=${userId}`, form);
      setMessage(`Item saved with ID: ${response.data.id}`);
    } catch (error) {
      const msg = error.response?.data?.message || "Item save failed.";
      setMessage(msg);
    }
  };

  return (
    <div className="container">
      <h2>Add / Edit Item</h2>
      <form onSubmit={handleSubmit}>
        <input name="title" placeholder="Title" onChange={handleChange} required />
        <input name="description" placeholder="Description" onChange={handleChange} />
        <input name="category" placeholder="Category" onChange={handleChange} required />
        <input name="location" placeholder="Location" onChange={handleChange} required />
        <input name="date" type="date" onChange={handleChange} />
        <select name="status" value={form.status} onChange={handleChange}>
          <option value="LOST">LOST</option>
          <option value="FOUND">FOUND</option>
          <option value="CLAIMED">CLAIMED</option>
          <option value="RETURNED">RETURNED</option>
        </select>
        <input name="imageUrl" placeholder="Image URL" onChange={handleChange} />
        <input name="expiryDate" type="date" onChange={handleChange} />
        <input name="contactInfo" placeholder="Contact Info" onChange={handleChange} />
        <button type="submit">Save Item</button>
      </form>
      <p>{message}</p>
    </div>
  );
}

export default AddEditItem;
